{"code":"import json
import re

# Load 2015 metadata
with open(locals()['var_function-call-15217179502760513550'], 'r') as f:
    metadata_list = json.load(f)

id_to_region = {str(item['article_id']): item['region'] for item in metadata_list}
print(f"Metadata sample IDs: {list(id_to_region.keys())[:10]}")

# Load articles
with open(locals()['var_function-call-11565805051991681784'], 'r') as f:
    articles_list = json.load(f)

print(f"Articles sample IDs: {[str(a['article_id']) for a in articles_list[:10]]}")

# Check overlap
overlap_count = 0
for a in articles_list:
    if str(a['article_id']) in id_to_region:
        overlap_count += 1
print(f"Overlap count: {overlap_count}")

# Classifier test
categories = {
    "World": ["president", "minister", "iraq", "war", "government", "official"],
    "Sports": ["game", "team", "win"],
    "Business": ["market", "price", "stock"],
    "Sci_Tech": ["google", "technology"]
}

def classify(text):
    text = text.lower()
    scores = {cat: 0 for cat in categories}
    for cat, keywords in categories.items():
        for kw in keywords:
            if kw in text:
                scores[cat] += 1
    if max(scores.values()) == 0:
        return "Unknown"
    return max(scores, key=scores.get)

# Test on first 5 overlapping
count = 0
debug_results = []
for article in articles_list:
    aid = str(article.get("article_id"))
    if aid in id_to_region:
        text = (article.get("title", "") + " " + article.get("description", "")).replace(chr(92), "")
        cat = classify(text)
        debug_results.append({"id": aid, "text": text[:100], "cat": cat})
        count += 1
        if count >= 5:
            break

print("__RESULT__:")
print(json.dumps(debug_results))"}

