with open(locals()['var_function-call-11565805051991681784'], 'r') as f:
    articles_list = json.load(f)

# Categories
categories = {
    "World": ["president", "minister", "government", "war", "official", "kill", "police", "united nations", "security", "leader", "iraq", "iran", "syria", "afghanistan", "military", "troops", "bomb", "blast", "attack", "peace", "talks", "china", "russia", "eu", "nato", "palestin", "israel", "gaza", "terror", "crisis"],
    "Sports": ["game", "team", "score", "cup", "win", "league", "season", "olympic", "champion", "player", "coach", "sport", "football", "soccer", "basketball", "baseball", "tennis", "golf"],
    "Business": ["market", "company", "stock", "price", "economy", "profit", "loss", "bank", "trade", "dollar", "euro", "invest", "deal", "oil", "fed", "sales", "revenue"],
    "Sci_Tech": ["technology", "science", "google", "nasa", "study", "space", "launch", "software", "internet", "web", "virus", "microsoft", "apple", "computer", "mobile", "phone"]
}

def classify(text):
    text = text.lower()
    scores = {cat: 0 for cat in categories}
    for cat, keywords in categories.items():
        for kw in keywords:
             if re.search(r'\b' + re.escape(kw) + r'\b', text):
                scores[cat] += 1
    if max(scores.values()) == 0:
        return "Unknown"
    return max(scores, key=scores.get)

